import React from 'react';
import { Routes, Route, Navigate } from 'react-router-dom';

// Context provider and route protection
import { AuthProvider } from './context/AuthContext';
import ProtectedRoute from './components/ProtectedRoute';

// Layout and pages
import Layout from './components/Layout';
import Login from './pages/Login';
import Home from './pages/Home';
import EtiquetasPage from './pages/EtiquetasPage';
import TrackingPage from './pages/TrackingPage';

/**
 * Top level application component.
 * Defines all routes and wraps them in AuthProvider for session context.
 */
function App() {
  return (
    <AuthProvider>
      <Routes>
        {/* Public route for login */}
        <Route path="/login" element={<Login />} />
        {/* Protected routes wrapped in Layout */}
        <Route
          path="/"
          element={
            <ProtectedRoute>
              <Layout />
            </ProtectedRoute>
          }
        >
          {/* Index/home page */}
          <Route index element={<Home />} />
          {/* React‑migrated modules */}
          <Route path="etiquetas" element={<EtiquetasPage />} />
          <Route path="rastreo" element={<TrackingPage />} />
        </Route>
        {/* Fallback: redirect anything unknown back to home */}
        <Route path="*" element={<Navigate to="/" replace />} />
      </Routes>
    </AuthProvider>
  );
}

export default App;
